import base64
import json
import os

from google.cloud import firestore
from google.cloud import pubsub_v1
from google.cloud import storage

def process_gcs_file(event, context):
    """
    Google Cloud Function that processes files from Cloud Storage,
    writes metadata to Firestore, and publishes a message to Pub/Sub.

    Args:
        event (dict): The Cloud Storage event payload.
        context (google.cloud.functions.Context): Metadata for the event.
    """

    bucket_name = event['bucket']
    file_name = event['name']
    file_generation = event['generation']
    content_type = event['contentType']
    time_created = event['timeCreated']
    updated = event['updated']
    size = event['size']

    print(f"Processing file: {file_name} from bucket: {bucket_name}")

    # Initialize Google Cloud clients
    firestore_client = firestore.Client()
    pubsub_publisher = pubsub_v1.PublisherClient()
    storage_client = storage.Client()

    # --- 1. Fetch file content from GCS (optional, but common for processing) ---
    # For this example, we'll just get metadata, but you could download the blob:
    # blob = storage_client.bucket(bucket_name).blob(file_name)
    # file_content = blob.download_as_text()
    # print(f"File content (first 100 chars): {file_content[:100]}...")

    # --- 2. Write file metadata to Firestore ---
    firestore_collection_name = os.environ.get('FIRESTORE_COLLECTION', 'gcs_file_metadata')
    doc_ref = firestore_client.collection(firestore_collection_name).document(f"{bucket_name}_{file_name}_{file_generation}")

    metadata = {
        'bucket': bucket_name,
        'fileName': file_name,
        'fileGeneration': file_generation,
        'contentType': content_type,
        'timeCreated': time_created,
        'updated': updated,
        'sizeBytes': int(size),
        'processedTimestamp': firestore.SERVER_TIMESTAMP
    }

    try:
        doc_ref.set(metadata)
        print(f"Successfully wrote metadata for {file_name} to Firestore document: {doc_ref.id}")
    except Exception as e:
        print(f"Error writing to Firestore: {e}")
        raise

    # --- 3. Publish a message to Pub/Sub ---
    pubsub_topic_name = os.environ.get('PUBSUB_TOPIC', 'gcs-file-processed')
    project_id = os.environ.get('GCP_PROJECT') # Automatically set by Cloud Functions

    if not project_id:
        print("GCP_PROJECT environment variable not set. Cannot publish to Pub/Sub.")
        raise ValueError("GCP_PROJECT environment variable is required for Pub/Sub.")

    topic_path = pubsub_publisher.topic_path(project_id, pubsub_topic_name)

    pubsub_message_data = {
        'bucket': bucket_name,
        'fileName': file_name,
        'fileGeneration': file_generation,
        'firestoreDocId': doc_ref.id,
        'eventType': 'gcs_file_processed'
    }

    try:
        # Pub/Sub message data must be bytes
        data_bytes = json.dumps(pubsub_message_data).encode('utf-8')
        future = pubsub_publisher.publish(topic_path, data_bytes)
        message_id = future.result()
        print(f"Published message for {file_name} to Pub/Sub topic {pubsub_topic_name} with ID: {message_id}")
    except Exception as e:
        print(f"Error publishing to Pub/Sub: {e}")
        raise

    print(f"Finished processing file: {file_name}")